// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/resource_data_detail_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/data/upload_queue.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/components/custom_alert_snack_bar.dart';
import 'package:baseball_detector_flutter/views/hooks/use_rerender.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/resource_details/components/resource_reanalyze_dialog.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/resource_details/components/resource_upload_dialog.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class ResourceDetailsSnackbar extends HookConsumerWidget {
  const ResourceDetailsSnackbar({
    required this.resource,
    super.key,
  });

  final ResourceData resource;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final rerender = useRerender();
    // 状態に応じたスナックバーの設定を取得
    final snackBarConfig = _getSnackBarConfig(
      context,
      ref,
      rerender,
    );

    // 表示するものがない場合は空のウィジェットを返す
    if (snackBarConfig == null) return const SizedBox.shrink();

    return CustomAlertSnackBar(
      showCloseIcon: false,
      backgroundColor: snackBarConfig.backgroundColor,
      foregroundColor: Colors.white,
      icon: snackBarConfig.icon,
      child: snackBarConfig.child,
    );
  }

  /// リソースの状態に応じたスナックバーの設定を取得する
  _SnackBarConfig? _getSnackBarConfig(
    BuildContext context,
    WidgetRef ref,
    VoidCallback rerender,
  ) {
    return switch (resource.statusType) {
      ResourceStatusType.analysisSucceeded => null,
      ResourceStatusType.onAnalysisServerQueue ||
      ResourceStatusType.inAnalysis =>
        _SnackBarConfig(
          backgroundColor: ColorManager.main,
          icon: Icons.info_outline,
          child: Text(context.l10n.resource_details_page__processing_video),
        ),
      ResourceStatusType.insufficientBalls ||
      ResourceStatusType.analysisFailed =>
        _SnackBarConfig(
          backgroundColor: ColorManager.error,
          icon: Icons.error_outline,
          child: Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(resource.statusType == ResourceStatusType.insufficientBalls
                  ? context.l10n.resource_details_page__analysis_limit_reached
                  : context.l10n.resource_details_page__analysis_failed),
              _buildTappableText(
                context.l10n.resource_details_page__try_again,
                () => _showResourceDialog(
                  context,
                  ref,
                  AppRouter.reanalyzeResourceDialog,
                  ResourceReanalyzeDialog(
                    resource: resource,
                    onSucceeded: () {
                      rerender();
                      // Also invalidate the resource data detail controller to force refresh
                      ref.invalidate(resourceDataDetailControllerProvider(
                        teamId: resource.teamId!,
                        sessionId: resource.sessionId!,
                        resourceId: resource.id!,
                      ));
                    },
                  ),
                ),
              ),
            ],
          ),
        ),
      ResourceStatusType.onLocalStorage => ref
              .read(uploadQueueProvider)
              .contains(resource)
          ? _SnackBarConfig(
              backgroundColor: ColorManager.main,
              icon: Icons.info_outline,
              child: Text(context.l10n.resource_details_page__on_upload_queue),
            )
          : _SnackBarConfig(
              backgroundColor: ColorManager.darkGrey,
              icon: Icons.error_outline,
              child: Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Text(context.l10n.resource_details_page__on_local_storage),
                  _buildTappableText(
                    context.l10n.resource_details_page__try_again,
                    () => _showResourceDialog(
                      context,
                      ref,
                      AppRouter.uploadResourceDialog,
                      ResourceUploadDialog(
                        resource: resource,
                        onSucceeded: rerender,
                      ),
                    ),
                  ),
                ],
              ),
            ),
      _ => null,
    };
  }

  /// リソース関連のダイアログを表示する
  void _showResourceDialog(
    BuildContext context,
    WidgetRef ref,
    String routeName,
    Widget dialog,
  ) {
    assert(!ref.read(uploadQueueProvider).contains(resource));

    showDialog(
      context: context,
      barrierDismissible: true,
      routeSettings: RouteSettings(
        name: routeName,
        arguments: {'resourceId': resource.id},
      ),
      builder: (_) => dialog,
    );
  }

  Widget _buildTappableText(String text, void Function() onTap) {
    return Consumer(
      builder: (context, ref, _) {
        final teamListState = ref.watch(teamListControllerProvider);
        final teamId = ref.watch(profileStorageProvider).getTeamId();

        return teamListState.fold(
          data: (teams) {
            final team = teams.where((team) => team.id == teamId!).firstOrNull;
            if (team?.teamPlanStatus.canAnalyze != true) {
              return const SizedBox.shrink();
            }

            return GestureDetector(
              onTap: onTap,
              child: Text(
                text,
                style: const TextStyle(decoration: TextDecoration.underline),
              ),
            );
          },
          error: (error) => const SizedBox.shrink(),
          loading: () => const SizedBox.shrink(),
        );
      },
    );
  }
}

/// スナックバーの設定を保持するクラス
class _SnackBarConfig {
  _SnackBarConfig({
    required this.backgroundColor,
    required this.icon,
    required this.child,
  });

  final Color backgroundColor;
  final IconData icon;
  final Widget child;
}

